-- Курс 69: Специалист по тендерам и госзакупкам (44-ФЗ, 223-ФЗ, ЕИС).
-- Полноценная программа: 8 модулей, 48 уроков.
INSERT INTO t_p78828167_tutor_platform_1.course_curricula
  (course_id, course_title, subject, grade_band, total_lessons, total_modules, estimated_hours,
   program_description, learning_outcomes, target_audience, prerequisites, methodology, final_project,
   certificate_available, generated_by, version, is_fallback, ai_error, age_rating, disclaimers)
VALUES (
  69,
  'Специалист по тендерам и госзакупкам с нуля: 44-ФЗ, 223-ФЗ, ЕИС',
  'tenders', 'adult', 48, 8, 36,
  'Профессиональный курс для старта в одной из самых востребованных удалённых профессий по данным HH.ru и SuperJob — специалист тендерного отдела. От полного нуля до уверенного участия в госзакупках и закупках компаний: законы 44-ФЗ и 223-ФЗ, работа в ЕИС и на электронных торговых площадках, поиск тендеров, подготовка заявок, обеспечение, контракты, электронные аукционы и защита прав в ФАС. Курс построен на реальных кейсах, шаблонах документов и пошаговых методиках.',
  '["Понимать различия и логику 44-ФЗ и 223-ФЗ","Искать прибыльные тендеры и оценивать риски участия","Регистрироваться и работать в ЕИС и на ЭТП","Готовить заявки и документацию без отклонений","Рассчитывать обеспечение заявки и контракта","Участвовать в электронных аукционах и конкурсах","Сопровождать контракт и контролировать исполнение","Защищать интересы через жалобы в ФАС","Собрать портфолио и резюме тендер-специалиста"]'::jsonb,
  'Взрослые от 18 лет, желающие освоить удалённую профессию с нуля: новички без опыта, специалисты по продажам и закупкам, предприниматели, фрилансеры, сотрудники компаний-поставщиков.',
  '["Базовые навыки работы за компьютером","Внимательность к деталям и документам","Желание работать с регламентами и сроками"]'::jsonb,
  'Методика «от закона к практике»: каждый теоретический блок сразу закрепляется разбором реальной закупки, шаблоном документа и чек-листом. Уроки чередуют теорию, практику на ЕИС/ЭТП, контрольные тесты в конце модулей и финальный проект — полный цикл участия в тендере. Дополнительные материалы: шаблоны заявок, калькуляторы обеспечения, чек-листы проверки документации, образцы жалоб в ФАС.',
  'Финальный проект: пройти полный цикл участия в учебном тендере — найти подходящую закупку в ЕИС, проанализировать документацию, рассчитать обеспечение и цену, подготовить и подать заявку, отработать сценарий электронного аукциона и оформить пакет документов для заключения контракта. Результат — готовый кейс для портфолио.',
  TRUE, 'manual_expert', 1, FALSE, NULL, '18+',
  '["Материалы курса носят образовательный характер. Законодательство РФ о закупках (44-ФЗ, 223-ФЗ) может меняться — перед участием в реальных закупках сверяйтесь с актуальной редакцией и при необходимости консультируйтесь с юристом.","Курс предназначен для лиц старше 18 лет. Соблюдайте налоговое и трудовое законодательство РФ.","При прохождении курса соблюдается 152-ФЗ «О персональных данных»."]'::jsonb
);

